class Solution {
    public int[] maximumCount(int[] nums, int[][] queries) {
        int[] result = new int[queries.length];
        int count = 0;
        int k = 0;

        for (int i = 0; i < queries.length; i++) {
            int idx = queries[i][0];
            int val = queries[i][1];

            if (isPrime(nums[idx]) && isPrime(nums[idx + k]) {
                count += val;
                k += nums[idx];
            }
            result[i] = count;
        }

        return result;
    }

    private boolean isPrime(int num) {
        for (int i = 2; i <= num / 2; i++) {
            if (num % i == 0) {
                return false;
            }
        }
        return true;
    }
}
